import PDFDocument from "pdfkit";
import qr from "qrcode";
import type { Prisma } from "#server/prisma/generated/prisma/browser";

type Participant = Prisma.ParticipantGetPayload<{
  include: {
    user: true,
    team: true,
  }
}>

type LayoutCircleOptions = {
  pos: Coordinates;
  radius: number;
};

type Coordinates = [x: number, y: number];

interface TextLine {
  text: string;
  fontSize: number;
  color: string;
  gapAfter?: boolean;
}

interface MeasuredTextLine extends TextLine {
  height: number;
  fittedFontSize: number;
}

interface DrawBadgeTextBlockOptions {
  circle?: LayoutCircleOptions;
  minimumLeftX?: number;
  circleSafeMargin?: number;
  textRightPadding?: number;
  textVerticalPadding?: number;
  baseTextGap?: number;
  origin?: Coordinates;
}

const BADGE_SIZE: Coordinates = [cmToPoints(10), cmToPoints(5)] as const;
const A4_SIZE: Coordinates = [cmToPoints(21), cmToPoints(29.7)] as const;
const A4_BADGE_GRID = {
  columns: 2,
  rows: 5,
} as const;

